#!/bin/sh

p=""
q=""
pvt_key="..."
pub_key=".7"
plaintext="1111111111111111222222222222222233333333333333334444444444444444555555555555555566666666666666667777777777777777888888888888888899999999999999990000000000000000"
ciphertext=""

if [ ! -f ./rsa ]; then
    echo "./rsa not found"
    exit 1
fi

echo "[KEYGEN]"
./rsa -keygen $p $q
printf "\n"

echo "[ENCRYPT]"
./rsa -encrypt $pub_key $plaintext
printf "\n"

echo "[DECRYPT]"
./rsa -decrypt $pvt_key $ciphertext
printf "\n"

